Adafruit_NeoPixel handles WS2812 timing on the RP2040 by bit-banging at 800 kHz with interrupts off during the show().

```cpp
#include <Arduino.h>
#include <Adafruit_NeoPixel.h>

const int LED_PIN = 15;
const int NUM_LEDS = 24;
const uint32_t CYCLE_MS = 6000;

Adafruit_NeoPixel ring(NUM_LEDS, LED_PIN, NEO_GRB + NEO_KHZ800);

void setup() {
  ring.begin();
  ring.setBrightness(40);
}

void loop() {
  uint16_t firstHue = (millis() % CYCLE_MS) * 65536UL / CYCLE_MS;
  ring.rainbow(firstHue);
  ring.show();
  delay(20);
}
```

Power-gate GPIO21 has to be HIGH for the onboard pixel to receive power.

```cpp
#include <Arduino.h>
#include <Adafruit_NeoPixel.h>

const int NEOPIXEL_PIN = 33;
const int NEOPIXEL_PWR = 21;

Adafruit_NeoPixel pixel(1, NEOPIXEL_PIN, NEO_GRB + NEO_KHZ800);

void setup() {
  pinMode(NEOPIXEL_PWR, OUTPUT);
  digitalWrite(NEOPIXEL_PWR, HIGH);
  pixel.begin();
  pixel.setBrightness(40);
}

void show(uint8_t r, uint8_t g, uint8_t b) {
  pixel.setPixelColor(0, pixel.Color(r, g, b));
  pixel.show();
}

void loop() {
  show(255, 0, 0); delay(250);
  show(0, 255, 0); delay(250);
  show(0, 0, 255); delay(250);
}
```

```cpp
#include <Arduino.h>
#include <Adafruit_NeoPixel.h>

const int LED_PIN = 5;
const int NUM_LEDS = 60;
const int FPS = 30;

Adafruit_NeoPixel strip(NUM_LEDS, LED_PIN, NEO_GRB + NEO_KHZ800);

int pos = 0;
int dir = 1;
uint32_t lastFrame = 0;

void setup() {
  strip.begin();
  strip.setBrightness(40);
}

void loop() {
  uint32_t now = millis();
  if (now - lastFrame < (1000 / FPS)) return;
  lastFrame = now;

  strip.clear();
  strip.setPixelColor(pos, strip.Color(255, 255, 255));
  strip.show();

  pos += dir;
  if (pos == NUM_LEDS - 1 || pos == 0) dir = -dir;
}
```

