#include <Arduino.h>
#include <Adafruit_NeoPixel.h>
#include <math.h>

const int PIXEL_PIN = 8;
const uint32_t PERIOD_MS = 2000;

Adafruit_NeoPixel pixel(1, PIXEL_PIN, NEO_GRB + NEO_KHZ800);

void setup() {
  pixel.begin();
}

void loop() {
  float t = (millis() % PERIOD_MS) / (float)PERIOD_MS;
  float s = (sinf(t * 2.0f * PI) + 1.0f) * 0.5f;
  uint8_t g = (uint8_t)(s * 200);
  pixel.setPixelColor(0, pixel.Color(0, g, 0));
  pixel.show();
  delay(15);
}
```

```cpp
#include <Arduino.h>
#include <Adafruit_NeoPixel.h>

const int LED_PIN = 14;
const int NUM_LEDS = 144;
const uint32_t STEP_MS = 80;

Adafruit_NeoPixel strip(NUM_LEDS, LED_PIN, NEO_GRB + NEO_KHZ800);
uint32_t lastStep = 0;
uint8_t offset = 0;

void setup() {
  strip.begin();
  strip.setBrightness(50);
}

void loop() {
  uint32_t now = millis();
  if (now - lastStep < STEP_MS) return;
  lastStep = now;

  strip.clear();
  for (int i = offset; i < NUM_LEDS; i += 3) {
    strip.setPixelColor(i, strip.Color(255, 255, 255));
  }
  strip.show();
  offset = (offset + 1) % 3;
}
```

S3 ADC is 12-bit (0-4095). Mapping the raw read straight into pixel index keeps the example simple; for production you'd low-pass filter and decay.

```cpp
#include <Arduino.h>
#include <Adafruit_NeoPixel.h>

const int LED_PIN = 5;
const int NUM_LEDS = 30;
const int MIC_PIN = 1;
const int ADC_MAX = 4095;

Adafruit_NeoPixel strip(NUM_LEDS, LED_PIN, NEO_GRB + NEO_KHZ800);

void setup() {
  strip.begin();
  strip.setBrightness(60);
}

void loop() {
  int raw = analogRead(MIC_PIN);
  int level = map(raw, 0, ADC_MAX, 0, NUM_LEDS);

  for (int i = 0; i < NUM_LEDS; i++) {
    if (i >= level) {
      strip.setPixelColor(i, 0);
    } else {
      uint8_t r = map(i, 0, NUM_LEDS - 1, 0, 255);
      uint8_t g = 255 - r;
      strip.setPixelColor(i, strip.Color(r, g, 0));
    }
  }
  strip.show();
  delay(20);
}
```

