Debounce the button by gating on a state change rather than instantaneous read.

```cpp
#include <Arduino.h>
#include <Adafruit_NeoPixel.h>

const int LED_PIN = 6;
const int BTN_PIN = 15;
const int NUM_LEDS = 16;

Adafruit_NeoPixel ring(NUM_LEDS, LED_PIN, NEO_GRB + NEO_KHZ800);
uint8_t state = 0;
bool lastBtn = HIGH;
uint32_t lastChange = 0;
const uint32_t DEBOUNCE_MS = 30;

void applyState() {
  uint32_t c = 0;
  switch (state) {
    case 0: c = ring.Color(255, 0, 0); break;
    case 1: c = ring.Color(0, 255, 0); break;
    case 2: c = ring.Color(0, 0, 255); break;
    case 3: c = 0; break;
  }
  for (int i = 0; i < NUM_LEDS; i++) ring.setPixelColor(i, c);
  ring.show();
}

void setup() {
  pinMode(BTN_PIN, INPUT_PULLUP);
  ring.begin();
  ring.setBrightness(50);
  applyState();
}

void loop() {
  bool now = digitalRead(BTN_PIN);
  if (now != lastBtn && (millis() - lastChange) > DEBOUNCE_MS) {
    lastChange = millis();
    if (lastBtn == HIGH && now == LOW) {
      state = (state + 1) % 4;
      applyState();
    }
    lastBtn = now;
  }
}
```

Cheap fire: per-pixel cooling with random heat injection, then map heat to a red->yellow palette.

```cpp
#include <Arduino.h>
#include <Adafruit_NeoPixel.h>

const int LED_PIN = 5;
const int NUM_LEDS = 60;
const uint8_t COOLING = 60;
const uint8_t SPARKING = 120;

Adafruit_NeoPixel strip(NUM_LEDS, LED_PIN, NEO_GRB + NEO_KHZ800);
uint8_t heat[NUM_LEDS];

uint32_t heatColor(uint8_t h) {
  uint8_t t192 = (uint16_t)h * 191 / 255;
  uint8_t heatramp = (t192 & 0x3F) << 2;
  if (t192 > 0x80)      return strip.Color(255,    255,     heatramp);
  else if (t192 > 0x40) return strip.Color(255,    heatramp, 0);
  else                  return strip.Color(heatramp, 0,      0);
}

void setup() {
  strip.begin();
  strip.setBrightness(80);
  randomSeed(esp_random());
}

void loop() {
  for (int i = 0; i < NUM_LEDS; i++) {
    int cool = random(0, ((COOLING * 10) / NUM_LEDS) + 2);
    heat[i] = (heat[i] > cool) ? heat[i] - cool : 0;
  }
  for (int k = NUM_LEDS - 1; k >= 2; k--) {
    heat[k] = (heat[k - 1] + heat[k - 2] + heat[k - 2]) / 3;
  }
  if (random(255) < SPARKING) {
    int y = random(7);
    heat[y] = min(255, heat[y] + random(160, 255));
  }
  for (int j = 0; j < NUM_LEDS; j++) strip.setPixelColor(j, heatColor(heat[j]));
  strip.show();
  delay(20);
}
```

NeoMatrix wraps NeoPixel with X/Y addressing. Layout flags depend on how the matrix is wired; this assumes top-left origin and progressive rows.

```cpp
#include <Arduino.h>
#include <Adafruit_GFX.h>
#include <Adafruit_NeoMatrix.h>
#include <Adafruit_NeoPixel.h>

const int LED_PIN = 5;
const int W = 16, H = 16;

Adafruit_NeoMatrix matrix(W, H, LED_PIN,
  NEO_MATRIX_TOP + NEO_MATRIX_LEFT + NEO_MATRIX_ROWS + NEO_MATRIX_PROGRESSIVE,
  NEO_GRB + NEO_KHZ800);

int x = W;
uint32_t lastStep = 0;

void setup() {
  matrix.begin();
  matrix.setBrightness(40);
  matrix.setTextWrap(false);
  matrix.setTextColor(matrix.Color(255, 0, 0));
}

void loop() {
  if (millis() - lastStep < 60) return;
  lastStep = millis();

  matrix.fillScreen(0);
  matrix.setCursor(x, 4);
  matrix.print("hello");
  matrix.show();

  if (--x < -40) x = W;
}
```
